    seen: set[str] = set()
    for e in edges:
        if e.retracted_at is not None:
            continue
        key = f"{e.src}->{e.dst}:{e.relation.value}"
        if key in seen:
            continue
        seen.add(key)
        label = f"{e.relation.value}\\n{e.confidence:.2f}"
        lines.append(
            f'    "{_safe_id(e.src)}" -> "{_safe_id(e.dst)}" '
